+using GCCM.Common.SystemFramework;
+using ProjectSight.Common.Components;
+using ProjectSight.Common.Components.Ignition;
+
+namespace ProjectSight.Tests.IntegrationTests.Records.Projects
+{
+    [TestClass]
+    public class ProjectCopyFilesTests : TestBase
+    {
+        private const string PROLOG_SUBDIR = "Prolog";
+        private const string DMS_FILES_SUBDIR = "DMS Files";
+        private const string PHOTOS_SUBDIR = "Photos";
+
+        [TestMethod]
+        public async Task CopyPhysicalFilesCopiesPrologSeedFilesIntoNewProjectFMSAndPhotosDirectories()
+        {
+            var dmsSourceDir = Path.Combine(Configuration.SQLFilesDirectory, PROLOG_SUBDIR, DMS_FILES_SUBDIR);
+            var photosSourceDir = Path.Combine(Configuration.SQLFilesDirectory, PROLOG_SUBDIR, PHOTOS_SUBDIR);
+
+            if (!Directory.Exists(dmsSourceDir))
+            {
+                Assert.Inconclusive($"Prolog DMS source dir not found: {dmsSourceDir}");
+            }
+
+            var expectedDmsFiles = Directory.GetFiles(dmsSourceDir, "*", SearchOption.TopDirectoryOnly)
+                .Select(Path.GetFileName)
+                .ToList();
+            expectedDmsFiles.Should().NotBeEmpty("seed Prolog DMS files must exist to be copied");
+
+            var expectedPhotoFiles = Directory.Exists(photosSourceDir)
+                ? Directory.GetFiles(photosSourceDir, "*", SearchOption.TopDirectoryOnly).Select(Path.GetFileName).ToList()
+                : new List<string>();
+
+            var createRequest = new CreateOrganizationRequest
+            {
+                Name = $"CopyPhysicalFiles {Generate.String(10)}",
+                AccountID = m_Account.AccountID,
+                CreateSampleProject = true,
+                DoNotIncludeSiteCaptureInSampleProject = true
+            };
+
+            try
+            {
+                await CreateOrganizationAsync(createRequest);
+
+                var defaultProjectId = ReadFirstProjectId(m_NewPortfolioId);
+                defaultProjectId.Should().BeGreaterThan(0, "sample project must be provisioned");
+
+                var requestedBy = GenerateRequestedBy(ContextUser, m_NewPortfolioId, defaultProjectId);
+
+                string newFmsDir;
+                string newPhotosDir;
+                using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, defaultProjectId))
+                {
+                    newFmsDir = ProjectSightDMSService.GetFMSDirectory(portfolioDB);
+                    newPhotosDir = ProjectSightDMSService.GetPhotosDirectory(portfolioDB);
+                }
+
+                Directory.Exists(newFmsDir).Should().BeTrue("new project FMS directory must be provisioned");
+
+                using (new AssertionScope())
+                {
+                    foreach (var expectedFile in expectedDmsFiles)
+                    {
+                        var dest = Path.Combine(newFmsDir, expectedFile);
+                        File.Exists(dest).Should().BeTrue($"FMS dest must contain {expectedFile}");
+                    }
+
+                    foreach (var expectedFile in expectedPhotoFiles)
+                    {
+                        var dest = Path.Combine(newPhotosDir, expectedFile);
+                        File.Exists(dest).Should().BeTrue($"Photos dest must contain {expectedFile}");
+                    }
+                }
+
+                foreach (var fileName in expectedDmsFiles)
+                {
+                    var dest = Path.Combine(newFmsDir, fileName);
+                    if (File.Exists(dest))
+                    {
+                        File.Delete(dest);
+                    }
+                }
+
+                using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, defaultProjectId))
+                {
+                    new ProjectSystem().CopyPhysicalFiles(portfolioDB);
+                }
+
+                using (new AssertionScope())
+                {
+                    foreach (var expectedFile in expectedDmsFiles)
+                    {
+                        var dest = Path.Combine(newFmsDir, expectedFile);
+                        File.Exists(dest).Should().BeTrue($"direct CopyPhysicalFiles must re-copy {expectedFile}");
+                    }
+                }
+            }
+            finally
+            {
+                RemoveNewOrganization();
+            }
+        }
+
+        private int ReadFirstProjectId(Guid portfolioId)
+        {
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedBy(ContextUser, portfolioId)))
+            {
+                return Global.IntFromDB(portfolioDB.ExecuteScalar("SELECT TOP 1 ProjectID FROM Projects WHERE Deleted = 0 ORDER BY ProjectID ASC"));
+            }
+        }
+    }
+}

