+using GCCM.Common.SystemFramework;
+using ProjectSight.Common.Components;
+
+namespace ProjectSight.Tests.IntegrationTests.Records.StaticSystem
+{
+    [TestClass]
+    public class StaticFileIDTests : TestBase
+    {
+        private int _createdFileId;
+        private string _createdFilePath;
+
+        public override async Task CustomTestCleanupAsync()
+        {
+            try
+            {
+                if (_createdFileId != 0)
+                {
+                    DeleteStaticFileRows(_createdFileId);
+                }
+
+                if (!string.IsNullOrEmpty(_createdFilePath) && File.Exists(_createdFilePath))
+                {
+                    try
+                    {
+                        File.Delete(_createdFilePath);
+                    }
+                    catch
+                    {
+                        // best-effort cleanup
+                    }
+                }
+            }
+            finally
+            {
+                await base.CustomTestCleanupAsync();
+            }
+        }
+
+        [TestMethod]
+        public void CreateStaticFileIDCreatesDMSFileRowAndCopiesPendingFileToFMSDirectory()
+        {
+            var requestedBy = GenerateRequestedByProject();
+            string fmsDir;
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                fmsDir = ProjectSightDMSService.GetFMSDirectory(portfolioDB);
+            }
+
+            var fileId = ProjectSight.DataAccess.StaticSystem.CreateStaticFileID(requestedBy, DMSFile.StaticTypes.FileBeingRetrieved);
+
+            fileId.Should().BeGreaterThan(0, "static file id must be returned");
+            _createdFileId = fileId;
+
+            var fileGuid = ReadDmsFileGuid(fileId);
+            fileGuid.Should().NotBe(Guid.Empty, "DMSFiles row must have been written with a GUID");
+
+            var fmsPath = Path.Combine(fmsDir, Global.CreateFileGUIDFromGUID(fileGuid.ToString()));
+            _createdFilePath = fmsPath;
+
+            using (new AssertionScope())
+            {
+                File.Exists(fmsPath).Should().BeTrue("pending thumbnail file must be copied into the FMS directory");
+                new FileInfo(fmsPath).Length.Should().Be(ThumbnailSystem.PendingFileSize, "copied file size must match the pending thumbnail size");
+                ReadDmsFileName(fileId).Should().Be(ThumbnailSystem.PendingFileName, "DMSFiles row must reference the pending file name");
+            }
+        }
+
+        #region Helpers
+
+        private Guid ReadDmsFileGuid(int fileId)
+        {
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject()))
+            {
+                return Global.GuidFromDB(portfolioDB.ExecuteScalar($"SELECT GUID FROM DMSFiles WHERE FileID = {fileId}"));
+            }
+        }
+
+        private string ReadDmsFileName(int fileId)
+        {
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject()))
+            {
+                return Global.StrFromDB(portfolioDB.ExecuteScalar($"SELECT FileName FROM DMSFiles WHERE FileID = {fileId}"));
+            }
+        }
+
+        private void DeleteStaticFileRows(int fileId)
+        {
+            try
+            {
+                using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject()))
+                {
+                    portfolioDB.ExecuteNonQuery($"DELETE FROM FileVersions WHERE FileID = {fileId}");
+                    portfolioDB.ExecuteNonQuery($"DELETE FROM DMSFiles WHERE FileID = {fileId}");
+                }
+            }
+            catch
+            {
+                // safe to ignore
+            }
+        }
+
+        #endregion // Helpers
+    }
+}

